import java.util.*;

public class RateLimiter {

    private final int maxRequests;
    private final long windowMs;

    // clientId -> [requestCount, windowStartMs]
    private final Map<String, long[]> clientState = new HashMap<>();

    public RateLimiter(int maxRequests, long windowMs) {
        this.maxRequests = maxRequests;
        this.windowMs = windowMs;
    }

    public boolean allowRequest(String clientId, long currentTimeMs) {
        // Check if the client is within their rate limit for the current window
        // Returns true if allowed, false if limit exceeded
        return false;
    }

    public int remainingQuota(String clientId, long currentTimeMs) {
        // Return the number of remaining requests in client's current window
        return maxRequests;
    }

    public static void main(String[] args) {
        RateLimiter limiter = new RateLimiter(3, 60_000L); // 3 req per minute

        long t = 0L;
        System.out.println(limiter.allowRequest("client-1", t));      // true
        System.out.println(limiter.allowRequest("client-1", t));      // true
        System.out.println(limiter.allowRequest("client-1", t));      // true
        System.out.println(limiter.allowRequest("client-1", t));      // false (limit exceeded)
        System.out.println(limiter.allowRequest("client-1", t + 61_000L)); // true (new window)
    }
}

import java.util.*;
import java.util.function.Supplier;

public class AggregatorGateway {

    public record ServiceCall(String key, Supplier<Map<String, Object>> fetcher) {}

    private final List<ServiceCall> registeredCalls = new ArrayList<>();

    public void registerCall(String key, Supplier<Map<String, Object>> fetcher) {
        registeredCalls.add(new ServiceCall(key, fetcher));
    }

    public Map<String, Object> aggregate() {
        // Execute all registered service calls and merge results
        // Each call's results are stored under its 'key' in the response
        return new LinkedHashMap<>();
    }

    public static void main(String[] args) {
        AggregatorGateway gateway = new AggregatorGateway();

        gateway.registerCall("user", () -> Map.of("name", "Alice", "email", "alice@example.com"));
        gateway.registerCall("orders", () -> Map.of("count", 5, "total", 250.00));
        gateway.registerCall("loyalty", () -> Map.of("points", 1200));

        Map<String, Object> response = gateway.aggregate();
        System.out.println("Keys: " + response.keySet());
        System.out.println("User name: " + ((Map<?,?>) response.get("user")).get("name"));
        System.out.println("Order count: " + ((Map<?,?>) response.get("orders")).get("count"));
    }
}
